// Honeypot + consent gate, then normalise. Return [] to stop silently.
const raw = $input.first().json;
const b = raw.body || raw;
if (b.company_size && String(b.company_size).trim() !== '') return [];
if (b.consent !== true && b.consent !== 'true') return [];
const email = String(b.email || '').trim().toLowerCase();
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) return [];
let website = String(b.website_url || '').trim();
if (website && !/^https?:\/\//i.test(website)) website = 'https://' + website;
if (!website) return [];
return [{ json: {
  name: String(b.name || '').trim(),
  email,
  phone: String(b.phone || '').trim(),
  business_name: String(b.business_name || '').trim(),
  website_url: website,
  location: String(b.location || '').trim(),
  trade: String(b.trade || '').trim()
} }];
